# 示例 2：批量创建相关文件并自动建立依赖关系
# 场景：为一个电商系统创建商品管理模块

# ==== 场景说明 ====
# 需求：创建商品管理功能，包括：
# 1. 商品类型定义 (product.types.ts)
# 2. 商品仓储层 (product.repository.ts)
# 3. 商品服务层 (product.service.ts)
# 4. 商品控制器 (product.controller.ts)

# ==== 在 Aider 中使用的指令示例 ====

# 首先明确项目结构
"""
项目结构：
src/
├── types/
│   └── product.types.ts
├── repositories/
│   └── product.repository.ts
├── services/
│   └── product.service.ts
└── controllers/
    └── product.controller.ts

请按顺序创建这些文件，确保：
1. 类型定义先于其他文件
2. 每个文件正确导入依赖
3. 接口保持一致
"""

# ==== 生成的代码 ====

# 文件：src/types/product.types.ts
from dataclasses import dataclass
from typing import List, Optional
from datetime import datetime
from decimal import Decimal
from enum import Enum

class ProductStatus(Enum):
    DRAFT = "draft"           # 草稿
    PUBLISHED = "published"   # 已发布
    ARCHIVED = "archived"     # 已归档

@dataclass
class ProductImage:
    """商品图片"""
    url: str
    alt: str
    is_primary: bool = False

@dataclass
class Product:
    """商品实体"""
    id: str
    name: str
    description: str
    price: Decimal
    stock: int
    category_id: str
    images: List[ProductImage]
    status: ProductStatus
    created_at: datetime
    updated_at: datetime
    tags: List[str] = None

    def __post_init__(self):
        if self.tags is None:
            self.tags = []

@dataclass
class CreateProductRequest:
    """创建商品请求"""
    name: str
    description: str
    price: Decimal
    stock: int
    category_id: str
    images: List[ProductImage]
    tags: List[str] = None

@dataclass
class UpdateProductRequest:
    """更新商品请求（所有字段可选）"""
    name: Optional[str] = None
    description: Optional[str] = None
    price: Optional[Decimal] = None
    stock: Optional[int] = None
    category_id: Optional[str] = None
    images: Optional[List[ProductImage]] = None
    status: Optional[ProductStatus] = None
    tags: Optional[List[str]] = None

# 文件：src/repositories/product.repository.ts
from typing import List, Optional
from decimal import Decimal
from .product_repository_base import ProductRepositoryBase
from ..types.product_types import Product, ProductStatus, CreateProductRequest, UpdateProductRequest

class ProductRepository(ProductRepositoryBase):
    """商品数据访问层"""

    async def find_by_id(self, product_id: str) -> Optional[Product]:
        """根据ID查找商品"""
        row = await self.db.fetch_one(
            "SELECT * FROM products WHERE id = ?", 
            product_id
        )
        return self._row_to_product(row) if row else None

    async def find_by_category(
        self, 
        category_id: str, 
        status: ProductStatus = ProductStatus.PUBLISHED,
        limit: int = 20,
        offset: int = 0
    ) -> List[Product]:
        """根据分类查找商品"""
        rows = await self.db.fetch_all(
            """SELECT * FROM products 
               WHERE category_id = ? AND status = ?
               ORDER BY created_at DESC
               LIMIT ? OFFSET ?""",
            (category_id, status.value, limit, offset)
        )
        return [self._row_to_product(row) for row in rows]

    async def create(self, request: CreateProductRequest) -> Product:
        """创建商品"""
        import uuid
        from datetime import datetime

        product = Product(
            id=str(uuid.uuid4()),
            name=request.name,
            description=request.description,
            price=request.price,
            stock=request.stock,
            category_id=request.category_id,
            images=request.images,
            status=ProductStatus.DRAFT,
            created_at=datetime.now(),
            updated_at=datetime.now(),
            tags=request.tags or []
        )

        # 数据库插入逻辑...
        return product

# 文件：src/services/product.service.ts
from typing import List, Optional
from decimal import Decimal
from .product_repository import ProductRepository
from ..types.product_types import (
    Product, ProductStatus, 
    CreateProductRequest, UpdateProductRequest
)

class ProductService:
    """商品业务逻辑层"""

    def __init__(self, repository: ProductRepository):
        self.repository = repository

    async def create_product(self, request: CreateProductRequest) -> Product:
        """创建商品（带业务验证）"""
        # 验证价格
        if request.price <= 0:
            raise ValueError("价格必须大于0")

        # 验证库存
        if request.stock < 0:
            raise ValueError("库存不能为负数")

        # 验证分类是否存在
        if not await self._category_exists(request.category_id):
            raise ValueError("分类不存在")

        return await self.repository.create(request)

    async def update_product(
        self, 
        product_id: str, 
        request: UpdateProductRequest
    ) -> Optional[Product]:
        """更新商品"""
        product = await self.repository.find_by_id(product_id)
        if not product:
            return None

        # 价格验证
        if request.price is not None and request.price <= 0:
            raise ValueError("价格必须大于0")

        # 更新商品
        updated = await self.repository.update(product_id, request)
        return updated

    async def publish_product(self, product_id: str) -> Product:
        """发布商品"""
        product = await self.repository.find_by_id(product_id)
        if not product:
            raise ValueError("商品不存在")

        if product.stock <= 0:
            raise ValueError("库存不足，无法发布")

        return await self.repository.update_status(
            product_id, 
            ProductStatus.PUBLISHED
        )

# 文件：src/controllers/product.controller.py
from typing import List
from fastapi import APIRouter, HTTPException, Depends
from decimal import Decimal
from .product_service import ProductService
from ..types.product_types import (
    Product, ProductStatus,
    CreateProductRequest, UpdateProductRequest
)

router = APIRouter(prefix="/products", tags=["商品管理"])

def get_product_service() -> ProductService:
    # 依赖注入实现
    pass

@router.post("/", response_model=Product)
async def create_product(
    request: CreateProductRequest,
    service: ProductService = Depends(get_product_service)
):
    """创建商品"""
    try:
        return await service.create_product(request)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

@router.get("/{product_id}", response_model=Product)
async def get_product(
    product_id: str,
    service: ProductService = Depends(get_product_service)
):
    """获取商品详情"""
    product = await service.get_product(product_id)
    if not product:
        raise HTTPException(status_code=404, detail="商品不存在")
    return product

@router.put("/{product_id}", response_model=Product)
async def update_product(
    product_id: str,
    request: UpdateProductRequest,
    service: ProductService = Depends(get_product_service)
):
    """更新商品"""
    product = await service.update_product(product_id, request)
    if not product:
        raise HTTPException(status_code=404, detail="商品不存在")
    return product

@router.post("/{product_id}/publish", response_model=Product)
async def publish_product(
    product_id: str,
    service: ProductService = Depends(get_product_service)
):
    """发布商品"""
    try:
        return await service.publish_product(product_id)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
