# ==== 第二步：添加功能 ====
# 指令：在 FileProcessor 类中添加文件列表和删除功能

# 扩展后的代码：
import * as fs from 'fs/promises';
import * as path from 'path';

export class FileProcessor {
    private basePath: string;

    constructor(basePath: string) {
        this.basePath = basePath;
    }

    async readFile(filename: string): Promise<string> {
        const filePath = path.join(this.basePath, filename);
        return await fs.readFile(filePath, 'utf-8');
    }

    async writeFile(filename: string, content: string): Promise<void> {
        const filePath = path.join(this.basePath, filename);
        await fs.writeFile(filePath, content, 'utf-8');
    }

    async listFiles(): Promise<string[]> {
        const entries = await fs.readdir(this.basePath);
        return entries.filter(async (entry) => {
            const stat = await fs.stat(path.join(this.basePath, entry));
            return stat.isFile();
        });
    }

    async deleteFile(filename: string): Promise<void> {
        const filePath = path.join(this.basePath, filename);
        await fs.unlink(filePath);
    }
}

# ==== 第三步：添加错误处理和类型定义 ====
# 指令：为 FileProcessor 添加完整的错误处理和类型定义

# 最终完善后的代码：
import * as fs from 'fs/promises';
import * as path from 'path';

export class FileProcessorError extends Error {
    constructor(message: string, public code: string) {
        super(message);
        this.name = 'FileProcessorError';
    }
}

export interface FileInfo {
    name: string;
    path: string;
    size: number;
    modifiedAt: Date;
}

export class FileProcessor {
    private basePath: string;

    constructor(basePath: string) {
        this.basePath = basePath;
    }

    private resolvePath(filename: string): string {
        const resolved = path.resolve(this.basePath, filename);
        if (!resolved.startsWith(this.basePath)) {
            throw new FileProcessorError(
                '路径遍历攻击检测到',
                'PATH_TRAVERSAL'
            );
        }
        return resolved;
    }

    async readFile(filename: string): Promise<string> {
        try {
            const filePath = this.resolvePath(filename);
            return await fs.readFile(filePath, 'utf-8');
        } catch (error) {
            if (error.code === 'ENOENT') {
                throw new FileProcessorError(
                    `文件不存在: ${filename}`,
                    'FILE_NOT_FOUND'
                );
            }
            throw error;
        }
    }

    async writeFile(filename: string, content: string): Promise<void> {
        try {
            const filePath = this.resolvePath(filename);
            await fs.writeFile(filePath, content, 'utf-8');
        } catch (error) {
            throw new FileProcessorError(
                `写入文件失败: ${filename}`,
                'WRITE_ERROR'
            );
        }
    }

    async listFiles(): Promise<FileInfo[]> {
        try {
            const entries = await fs.readdir(this.basePath);
            const fileInfos: FileInfo[] = [];

            for (const entry of entries) {
                const fullPath = path.join(this.basePath, entry);
                const stat = await fs.stat(fullPath);

                if (stat.isFile()) {
                    fileInfos.push({
                        name: entry,
                        path: fullPath,
                        size: stat.size,
                        modifiedAt: stat.mtime
                    });
                }
            }

            return fileInfos.sort((a, b) => 
                b.modifiedAt.getTime() - a.modifiedAt.getTime()
            );
        } catch (error) {
            throw new FileProcessorError(
                '列出文件失败',
                'LIST_ERROR'
            );
        }
    }

    async deleteFile(filename: string): Promise<void> {
        try {
            const filePath = this.resolvePath(filename);
            await fs.unlink(filePath);
        } catch (error) {
            if (error.code === 'ENOENT') {
                throw new FileProcessorError(
                    `文件不存在: ${filename}`,
                    'FILE_NOT_FOUND'
                );
            }
            throw new FileProcessorError(
                `删除文件失败: ${filename}`,
                'DELETE_ERROR'
            );
        }
    }

    async exists(filename: string): Promise<boolean> {
        try {
            const filePath = this.resolvePath(filename);
            await fs.access(filePath);
            return true;
        } catch {
            return false;
        }
    }
}
```



## 常见错误

- 1. 上下文缺失导致代码质量下降
   - 没有指定目标文件，AI 可能生成到错误的位置
   - 没有描述依赖关系，导致代码不完整或循环依赖
   - 缺少类型信息，导致生成的代码缺少类型注解
- 2. 过大的单次生成请求
   - 试图一次性生成整个模块，容易产生错误
   - 上下文窗口有限，大请求可能导致关键信息被截断
   - 不利于版本控制和代码审查
- 3. 文件依赖顺序混乱
   - 在类型定义前就使用该类型
   - 循环依赖未及时发现和解决
   - import 语句错误或遗漏
- 4. 忽略项目约定和风格
   - 不遵循现有的命名规范
   - 不使用项目已有的工具函数
   - 代码风格与项目其他部分不一致
- 5. 路径引用错误
   - 使用错误的相对路径或绝对路径
   - 未考虑不同操作系统路径分隔符差异
   - 引用不存在的文件或模块


## 最佳实践

- 1. 始终使用明确的上下文锚定
   - 在请求中明确指定目标文件路径
   - 描述该文件在整个项目中的位置和作用
   - 提供相关的类型定义和接口信息
   示例：「在 src/services/user.service.ts 中添加新方法，继承现有的 BaseService 类」
- 2. 采用渐进式生成策略
   - 先从核心类型和接口开始
   - 按依赖层次从底层到上层依次生成
   - 每次修改后验证功能正常再继续
   建议：大型模块拆分为多次对话完成，每次聚焦一个文件
- 3. 保持清晰的依赖关系图
   - 在生成新文件时说明依赖的其他文件
   - 确认 import 语句正确性
   - 检查是否有循环依赖风险
   工具：使用 IDE 的依赖图功能或 import 插件
- 4. 利用 Aider 的多文件编辑能力
   - 使用 /multi 命令同时编辑多个文件
   - 在一次请求中描述多个相关文件的修改
   - 确保修改保持一致性
   示例：「更新 user.service.ts 和 user.controller.ts，将新方法暴露为 API」
- 5. 验证和测试驱动生成
   - 生成后立即运行测试
   - 发现问题及时反馈给 AI 修正
   - 保持测试覆盖率
   流程：生成代码 → 运行测试 → 修复问题 → 继续完善
- 6. 使用 HEAD 锚定保持上下文
   - 复杂项目中定期使用 /read 获取文件内容
   - 帮助 AI 保持对项目的准确理解
   - 避免上下文漂移
   提示：在长对话中每 5-10 次交互后重新读取关键文件
- 7. 遵循项目已有的模式和约定
   - 在生成前先了解项目的代码风格
   - 使用项目中的公共工具和辅助函数
   - 保持命名和格式的一致性
   做法：先查看 2-3 个类似文件作为参考

