### 示例2：Go + Rust 跨语言性能关键模块

#### Go端（高性能HTTP服务）

go
// backend/services/compute/service.go
package compute

import (
    "context"
    "errors"
    "time"
)

var ErrInvalidInput = errors.New("invalid input parameters")

// ComputeRequest 定义计算请求
type ComputeRequest struct {
    Operation string    `json:"operation"` // "add", "multiply", "matrix_multiply"
    Data      []float64 `json:"data"`
    MatrixA   [][]float64 `json:"matrix_a,omitempty"`
    MatrixB   [][]float64 `json:"matrix_b,omitempty"`
}

// ComputeResponse 定义计算响应
type ComputeResponse struct {
    Result    interface{} `json:"result"`
    Duration  time.Duration `json:"duration_ms"`
    Precision string       `json:"precision"`
}

// Service 计算服务接口
type Service interface {
    Process(ctx context.Context, req *ComputeRequest) (*ComputeResponse, error)
}

// DefaultService 默认实现
type DefaultService struct {
    precision string
}

func NewService(precision string) *DefaultService {
    return &DefaultService{precision: precision}
}

func (s *DefaultService) Process(ctx context.Context, req *ComputeRequest) (*ComputeResponse, error) {
    start := time.Now()

    var result interface{}
    var err error

    switch req.Operation {
    case "add":
        result, err = s.add(req.Data)
    case "multiply":
        result, err = s.multiply(req.Data)
    case "matrix_multiply":
        result, err = s.matrixMultiply(req.MatrixA, req.MatrixB)
    default:
        return nil, ErrInvalidInput
    }

    if err != nil {
        return nil, err
    }

    return &ComputeResponse{
        Result:    result,
        Duration:  time.Since(start),
        Precision: s.precision,
    }, nil
}

func (s *DefaultService) add(data []float64) (float64, error) {
    if len(data) < 2 {
        return 0, ErrInvalidInput
    }
    var sum float64
    for _, v := range data {
        sum += v
    }
    return sum, nil
}

func (s *DefaultService) multiply(data []float64) (float64, error) {
    if len(data) < 2 {
        return 0, ErrInvalidInput
    }
    product := 1.0
    for _, v := range data {
        product *= v
    }
    return product, nil
}

func (s *DefaultService) matrixMultiply(a, b [][]float64) ([][]float64, error) {
    if len(a) == 0 || len(b) == 0 || len(a[0]) != len(b) {
        return nil, ErrInvalidInput
    }

    rowsA, colsA := len(a), len(a[0])
    colsB := len(b[0])

    result := make([][]float64, rowsA)
    for i := range result {
        result[i] = make([]float64, colsB)
    }

    for i := 0; i < rowsA; i++ {
        for j := 0; j < colsB; j++ {
            for k := 0; k < colsA; k++ {
                result[i][j] += a[i][k] * b[k][j]
            }
        }
    }

    return result, nil
}


#### Rust端（性能关键计算）

rust
// rust_compute/src/lib.rs
use serde::{Deserialize, Serialize};
use std::time::Instant;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComputeRequest {
    pub operation: String,
    pub data: Option<Vec<f64>>,
    #[serde(rename = "matrixA")]
    pub matrix_a: Option<Vec<Vec<f64>>>,
    #[serde(rename = "matrixB")]
    pub matrix_b: Option<Vec<Vec<f64>>>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComputeResponse {
    pub result: ComputeResult,
    #[serde(rename = "durationMs")]
    pub duration_ms: f64,
    pub precision: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum ComputeResult {
    Scalar(f64),
    Matrix(Vec<Vec<f64>>),
}

#[derive(Debug, Clone)]
pub enum ComputeError {
    InvalidInput(String),
    DimensionMismatch(String),
}

impl std::fmt::Display for ComputeError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ComputeError::InvalidInput(msg) => write!(f, "Invalid input: {}", msg),
            ComputeError::DimensionMismatch(msg) => write!(f, "Dimension mismatch: {}", msg),
        }
    }
}

impl std::error::Error for ComputeError {}

pub struct ComputeService {
    precision: String,
}

impl ComputeService {
    pub fn new(precision: String) -> Self {
        Self { precision }
    }

    pub fn process(&self, req: ComputeRequest) -> Result<ComputeResponse, ComputeError> {
        let start = Instant::now();

        let result = match req.operation.as_str() {
            "add" => {
                let data = req.data.ok_or_else(|| {
                    ComputeError::InvalidInput("data field required".to_string())
                })?;
                self.add(&data)?
            },
            "multiply" => {
                let data = req.data.ok_or_else(|| {
                    ComputeError::InvalidInput("data field required".to_string())
                })?;
                self.multiply(&data)?
            },
            "matrix_multiply" => {
                let matrix_a = req.matrix_a.ok_or_else(|| {
                    ComputeError::InvalidInput("matrixA field required".to_string())
                })?;
                let matrix_b = req.matrix_b.ok_or_else(|| {
                    ComputeError::InvalidInput("matrixB field required".to_string())
                })?;
                self.matrix_multiply(&matrix_a, &matrix_b)?
            },
            _ => {
                return Err(ComputeError::InvalidInput(format!(
                    "Unknown operation: {}",
                    req.operation
                )));
            }
        };

        Ok(ComputeResponse {
            result,
            duration_ms: start.elapsed().as_secs_f64() * 1000.0,
            precision: self.precision.clone(),
        })
    }

    fn add(&self, data: &[f64]) -> Result<ComputeResult, ComputeError> {
        if data.len() < 2 {
            return Err(ComputeError::InvalidInput(
                "At least 2 elements required".to_string(),
            ));
        }
        let sum: f64 = data.iter().sum();
        Ok(ComputeResult::Scalar(sum))
    }

    fn multiply(&self, data: &[f64]) -> Result<ComputeResult, ComputeError> {
        if data.len() < 2 {
            return Err(ComputeError::InvalidInput(
                "At least 2 elements required".to_string(),
            ));
        }
        let product: f64 = data.iter().product();
        Ok(ComputeResult::Scalar(product))
    }

    fn matrix_multiply(
        &self,
        a: &[Vec<f64>],
        b: &[Vec<f64>],
    ) -> Result<ComputeResult, ComputeError> {
        if a.is_empty() || b.is_empty() {
            return Err(ComputeError::InvalidInput(
                "Matrices cannot be empty".to_string(),
            ));
        }

        let rows_a = a.len();
        let cols_a = a[0].len();
        let rows_b = b.len();
        let cols_b = b[0].len();

        if cols_a != rows_b {
            return Err(ComputeError::DimensionMismatch(format!(
                "Matrix dimensions mismatch: {}x{} cannot multiply with {}x{}",
                rows_a, cols_a, rows_b, cols_b
            )));
        }

        // 优化的矩阵乘法实现
        let mut result = vec![vec![0.0; cols_b]; rows_a];

        for i in 0..rows_a {
            for j in 0..cols_b {
                for k in 0..cols_a {
                    result[i][j] += a[i][k] * b[k][j];
                }
            }
        }

        Ok(ComputeResult::Matrix(result))
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_add() {
        let service = ComputeService::new("f64".to_string());
        let req = ComputeRequest {
            operation: "add".to_string(),
            data: Some(vec![1.0, 2.0, 3.0]),
            matrix_a: None,
            matrix_b: None,
        };
        let resp = service.process(req).unwrap();
        match resp.result {
            ComputeResult::Scalar(val) => assert!((val - 6.0).abs() < f64::EPSILON),
            _ => panic!("Expected scalar result"),
        }
    }

    #[test]
    fn test_matrix_multiply() {
        let service = ComputeService::new("f64".to_string());
        let a = vec![vec![1.0, 2.0], vec![3.0, 4.0]];
        let b = vec![vec![5.0, 6.0], vec![7.0, 8.0]];

        let req = ComputeRequest {
            operation: "matrix_multiply".to_string(),
            data: None,
            matrix_a: Some(a),
            matrix_b: Some(b),
        };

        let resp = service.process(req).unwrap();
        match resp.result {
            ComputeResult::Matrix(m) => {
                assert!((m[0][0] - 19.0).abs() < f64::EPSILON);
                assert!((m[0][1] - 22.0).abs() < f64::EPSILON);
                assert!((m[1][0] - 43.0).abs() < f64::EPSILON);
                assert!((m[1][1] - 50.0).abs() < f64::EPSILON);
            },
            _ => panic!("Expected matrix result"),
        }
    }
}


