// 示例4：Rust Web服务（rust_service/src/main.rs）
use actix_web::{web, App, HttpServer, HttpResponse, middleware};
use serde::{Deserialize, Serialize};
use chrono::Utc;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ApiResponse<T: Serialize> {
    pub success: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub data: Option<T>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<String>,
}

#[derive(Debug, Clone, Serialize)]
pub struct HealthStatus {
    pub status: String,
    pub service: String,
    pub timestamp: String,
}

/// 健康检查端点
async fn health_check() -> HttpResponse {
    let status = HealthStatus {
        status: "healthy".to_string(),
        service: "rust-service".to_string(),
        timestamp: Utc::now().to_rfc3339(),
    };

    HttpResponse::Ok().json(ApiResponse {
        success: true,
        data: Some(status),
        error: None,
    })
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    println!("Starting Rust service on http://127.0.0.1:8080");

    HttpServer::new(|| {
        App::new()
            // 添加日志中间件
            .wrap(middleware::Logger::default())
            // 配置健康检查路由
            .route("/health", web::get().to(health_check))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}
```



## 常见错误

- 在多语言项目中未明确指定语言上下文，导致Aider生成混合语法（如在Python文件中使用TypeScript的类型语法）
- 跨语言类型定义不同步：修改了Python的Pydantic模型但忘记同步更新TypeScript接口
- 在Go代码中使用Rust的所有权语法或在Python中使用Rust的Result模式，造成语言特性污染
- 忽略各语言的代码格式化规范，导致生成的代码风格不统一
- 在依赖管理中混用包管理工具，如同时使用pip和poetry管理Python依赖
- 未隔离不同语言的运行环境，导致依赖版本冲突或命名空间污染
- 在类型映射时不考虑JSON序列化差异（如Python的snake_case与TypeScript的camelCase）
- 跨语言调用时忽略错误处理模式的差异（如Go的多返回值error与Rust的Result枚举）


## 最佳实践

- 使用OpenAPI/Protobuf等共享契约定义跨语言数据类型，通过代码生成工具自动生成各语言的类型定义，确保类型一致性
- 在项目根目录创建.aider.conf.yml配置文件，明确指定主语言和支持的语言列表，帮助Aider正确识别上下文
- 建立统一的命名约定规范，明确snake_case、camelCase、PascalCase在各语言中的使用场景
- 使用Docker或podman容器化不同语言的服务，确保环境一致性和依赖隔离
- 采用monorepo结构管理多语言项目，使用Nx、Pants或Turborepo等工具统一构建流程
- 在Aider中使用--file参数明确指定要编辑的文件路径，避免编辑范围蔓延到其他语言的文件
- 为每种语言配置独立的格式化工具和CI检查（如black/prettier/gofmt/rustfmt），确保代码风格统一
- 跨语言重构时使用共享契约优先策略：先修改契约定义，再重新生成各语言的实现代码

