#!/usr/bin/env python3
import subprocess
import json

def run_quality_check(file_path):
    """执行pylint代码质量检查"""
    try:
        result = subprocess.run(
            ['pylint', file_path, '--output-format=json'],
            capture_output=True,
            text=True,
            timeout=30
        )
        issues = json.loads(result.stdout) if result.stdout else []
        return {'status': 'success' if not issues else 'issues_found', 'count': len(issues)}
    except FileNotFoundError:
        return {'status': 'error', 'message': '请安装pylint: pip install pylint'}
    except subprocess.TimeoutExpired:
        return {'status': 'error', 'message': '检查超时'}

if __name__ == '__main__':
    result = run_quality_check('example.py')
    print(json.dumps(result, indent=2))

